import { registerRootComponent } from 'expo';
import React, { useState, useEffect } from 'react';
import { View, Text, ActivityIndicator, StyleSheet, TouchableOpacity, Image, Platform } from 'react-native';

import { Auth } from './utils/auth';
import { ThemeProvider, useTheme } from './theme/ThemeContext';
import { isWideWeb } from './utils/platform';
import { Storage, KEYS, initStorage } from './utils/storage';
import WelcomeScreen       from './screens/WelcomeScreen';
import OnboardingScreen    from './screens/OnboardingScreen';
import AuthScreen          from './screens/AuthScreen';
import HomeScreen          from './screens/HomeScreen';
import FoodScannerScreen   from './screens/FoodScannerScreen';
import FoodLogScreen       from './screens/FoodlogScreen';
import MyPlanScreen        from './screens/MyPlanScreen';
import TrackerScreen       from './screens/TrackerScreen';
import ProgressScreen      from './screens/ProgressScreen';
import HealthScreen        from './screens/HealthScreen';
import MealStudioScreen    from './screens/MealStudioScreen';
import ARScreen            from './screens/ARScreen';
import ProfileScreen       from './screens/ProfileScreen';
import SettingsScreen      from './screens/SettingsScreen';
import WorkoutSessionScreen from './screens/WorkoutSessionScreen';
import BarcodeScanScreen   from './screens/BarcodeScanScreen';
import WeeklyReviewScreen  from './screens/WeeklyReviewScreen';
import MeasurementsScreen  from './screens/MeasurementsScreen';
import BottomNav           from './components/BottomNav';
import WebLayout           from './components/WebLayout';
import SplashScreen        from './components/SplashScreen';

import AsyncStorage from '@react-native-async-storage/async-storage';

const ONBOARDING_KEY = 'greengain_onboarding_complete';
const ONBOARDING_DATA_KEY = 'greengain_onboarding_data';
const LEGACY_ONBOARDING_KEY = 'fitlife_onboarding_complete';
const AUTHED = ['home', 'scanner', 'foodlog', 'plan', 'tracker', 'ar', 'profile', 'settings', 'progress', 'health', 'mealstudio', 'workoutsession', 'barcode', 'weeklyreview', 'measurements'];

function App() {
  const { C } = useTheme();
  const s = makeStyles(C);
  const [screen, setScreen] = useState('loading');
  const [screenParams, setScreenParams] = useState(null);
  const [user, setUser]     = useState(null);
  const [error, setError]   = useState(null);

  useEffect(() => { initStorage(); }, []);

  useEffect(() => {
    const MIN_SPLASH_MS = 2200;
    const splashStart = Date.now();
    const advance = (target) => {
      const elapsed = Date.now() - splashStart;
      const wait = Math.max(0, MIN_SPLASH_MS - elapsed);
      setTimeout(() => setScreen(target), wait);
    };
    const init = async () => {
      let target = 'welcome';
      let nextUser = null;
      try {
        const legacySession = await AsyncStorage.getItem('fitlife_session_v2');
        if (legacySession) {
          await AsyncStorage.setItem('greengain_session_v2', legacySession);
          await AsyncStorage.removeItem('fitlife_session_v2');
        }
        const legacyOnboarding = await AsyncStorage.getItem(LEGACY_ONBOARDING_KEY);
        if (legacyOnboarding) {
          await AsyncStorage.setItem(ONBOARDING_KEY, legacyOnboarding);
          await AsyncStorage.removeItem(LEGACY_ONBOARDING_KEY);
        }
        const u = await Auth.getSession();
        if (u) {
          const uid = u?.email || u?.uid;
          let userOnboarding = null;
          if (uid) {
            try { userOnboarding = await Storage.get(KEYS.ONBOARDING(uid)); } catch {}
          }
          nextUser = u;
          target = userOnboarding ? 'home' : 'onboarding';
        }
      } catch {}
      if (nextUser) setUser(nextUser);
      advance(target);
    };
    init();
  }, []);

  const navigate     = (to, params) => { setScreenParams(params || null); setScreen(to); };
  const handleLogout = ()   => { setUser(null); setScreen('welcome'); };

  const handleLogin = async (u) => {
    setUser(u);
    const uid = u?.email || u?.uid;
    try {
      if (uid) {
        const userOnboarding = await Storage.get(KEYS.ONBOARDING(uid));
        if (userOnboarding) { setScreen('home'); return; }
      }
    } catch {}
    setScreen('onboarding');
  };

  const handleOnboardingComplete = async (data) => {
    try {
      const uid = user?.email || user?.uid;
      if (uid) {
        await Storage.set(KEYS.ONBOARDING(uid), {
          ...data,
          completedAt: Date.now(),
          email: user?.email,
          fullName: user?.fullName,
        });
      }
      await AsyncStorage.setItem(ONBOARDING_DATA_KEY, JSON.stringify(data));
    } catch (e) {
      console.warn('Failed to save onboarding data:', e);
    }
    setScreen('home');
  };

  const updateUser = async (u) => {
    try {
      const fresh = await Auth.getUserData(u?.uid);
      setUser(fresh || u);
    } catch { setUser(u); }
  };

  if (error) {
    return (
      <View style={s.errorScreen}>
        <View style={s.errorIcon}><Text style={s.errorIconText}>!</Text></View>
        <Text style={s.errorTitle}>Something went wrong</Text>
        <Text style={s.errorText}>{error}</Text>
        <TouchableOpacity style={s.errorBtn} onPress={() => { setError(null); setScreen('welcome'); }}>
          <Text style={s.errorBtnText}>Restart</Text>
        </TouchableOpacity>
      </View>
    );
  }

  const renderScreen = () => {
    switch (screen) {
      case 'loading':
        return <SplashScreen />;
      case 'welcome':
        return <WelcomeScreen onStart={() => setScreen('auth')} />;
      case 'auth':
        return <AuthScreen onLogin={handleLogin} initialMode="signup" />;
      case 'onboarding':
        return <OnboardingScreen onComplete={handleOnboardingComplete} user={user} />;
      case 'home':    return <HomeScreen user={user} onNavigate={navigate} onUserUpdate={updateUser} />;
      case 'scanner': return <FoodScannerScreen user={user} onUserUpdate={updateUser} onAddToLog={() => navigate('foodlog')} />;
      case 'foodlog': return <FoodLogScreen user={user} onNavigate={navigate} />;
      case 'plan':    return <MyPlanScreen user={user} onNavigate={navigate} />;
      case 'tracker': return <TrackerScreen user={user} />;
      case 'progress': return <ProgressScreen user={user} onNavigate={navigate} />;
      case 'health':  return <HealthScreen user={user} onNavigate={navigate} />;
      case 'mealstudio': return <MealStudioScreen user={user} onNavigate={navigate} />;
      case 'ar':      return <ARScreen />;
      case 'profile': return <ProfileScreen user={user} onLogout={handleLogout} onNavigate={navigate} />;
      case 'settings': return <SettingsScreen onNavigate={navigate} />;
      case 'workoutsession': return <WorkoutSessionScreen user={user} params={screenParams} onNavigate={navigate} />;
      case 'barcode':     return <BarcodeScanScreen user={user} onNavigate={navigate} />;
      case 'weeklyreview': return <WeeklyReviewScreen user={user} onNavigate={navigate} />;
      case 'measurements': return <MeasurementsScreen user={user} onNavigate={navigate} />;
      default:        return null;
    }
  };

  const isAuthed = AUTHED.includes(screen);

  if (isWideWeb && isAuthed) {
    return (
      <WebLayout current={screen} onNavigate={navigate} user={user}>
        {renderScreen()}
      </WebLayout>
    );
  }

  return (
    <View style={s.root}>
      <View style={s.content}>{renderScreen()}</View>
      {isAuthed && <BottomNav current={screen} onNavigate={navigate} />}
    </View>
  );
}

const makeStyles = (C) => StyleSheet.create({
  root: { flex: 1, backgroundColor: C.bg },
  content: { flex: 1 },
  loading: { flex: 1, backgroundColor: C.bg, alignItems: 'center', justifyContent: 'center', overflow: 'hidden' },
  splashGlow: {
    position: 'absolute', width: 300, height: 300, borderRadius: 150,
    backgroundColor: C.greenGlow2,
    ...(Platform.OS === 'web' ? { filter: 'blur(80px)' } : { opacity: 0.15 }),
  },
  splashLogo: { width: 100, height: 100 },
  splashName: { color: C.white, fontSize: 34, fontWeight: '900', marginTop: 20, letterSpacing: 3 },
  errorScreen: { flex: 1, backgroundColor: C.bg, alignItems: 'center', justifyContent: 'center', padding: 40 },
  errorIcon: { width: 56, height: 56, borderRadius: 28, backgroundColor: C.danger + '20', alignItems: 'center', justifyContent: 'center', marginBottom: 20 },
  errorIconText: { color: C.danger, fontSize: 24, fontWeight: '900' },
  errorTitle: { color: C.white, fontSize: 22, fontWeight: '800', marginBottom: 12 },
  errorText: { color: C.muted, fontSize: 14, textAlign: 'center', marginBottom: 28, lineHeight: 22 },
  errorBtn: { backgroundColor: C.green, paddingVertical: 16, paddingHorizontal: 40, borderRadius: 16 },
  errorBtnText: { color: C.bg, fontWeight: '900', fontSize: 15, letterSpacing: 1 },
});

function Root() {
  return (
    <ThemeProvider>
      <App />
    </ThemeProvider>
  );
}

registerRootComponent(Root);

module.exports = function(api) {
  api.cache(true);
  return {
    presets: ['babel-preset-expo'],
  };
};

import React, { useState, useEffect, useCallback } from 'react';
import {
  StyleSheet, Text, View, TouchableOpacity, ActivityIndicator, Alert,
} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { useTheme } from '../theme/ThemeContext';
import { adaptPlan } from '../utils/planGenerator';
import { buildWeeklyContext } from '../utils/planAdapter';

const ONBOARDING_DATA_KEY = 'greengain_onboarding_data';

export default function AdaptiveCoachingCard({ user, plan, onPlanUpdate }) {
  const { C } = useTheme();
  const s = makeStyles(C);
  const uid = user?.uid;
  const userKey = user?.email || user?.uid;
  const [ctx, setCtx] = useState(null);
  const [adapting, setAdapting] = useState(false);

  const loadCtx = useCallback(async () => {
    if (!plan || !uid) return;
    try { setCtx(await buildWeeklyContext(uid, plan)); } catch {}
  }, [plan, uid]);

  useEffect(() => { loadCtx(); }, [loadCtx]);

  if (!plan) return null;

  const adaptNow = async () => {
    try {
      setAdapting(true);
      const raw = await AsyncStorage.getItem(ONBOARDING_DATA_KEY);
      const ob = raw ? JSON.parse(raw) : (plan.userProfile || {});
      const fresh = await buildWeeklyContext(uid, plan);
      const updated = await adaptPlan(plan, ob, fresh, userKey);
      if (updated) {
        onPlanUpdate && onPlanUpdate(updated);
        setCtx(await buildWeeklyContext(uid, updated));
      } else {
        Alert.alert('Adaptation failed', 'Please try again in a moment.');
      }
    } catch (e) {
      Alert.alert('Error', e.message || 'Adaptation failed.');
    } finally {
      setAdapting(false);
    }
  };

  return (
    <View style={s.adaptCard}>
      <View style={s.adaptHeader}>
        <Text style={s.adaptTitle}>Adaptive Coaching</Text>
        {ctx?.workout?.adherencePct !== null && ctx?.workout?.adherencePct !== undefined && (
          <View style={s.adhPill}>
            <Text style={s.adhPillText}>{ctx.workout.adherencePct}% adherence</Text>
          </View>
        )}
      </View>
      <View style={s.statsRow}>
        <View style={s.statBox}>
          <Text style={s.statVal}>
            {ctx?.weight?.observedKgPerWeek !== undefined && ctx?.weight?.observedKgPerWeek !== null
              ? `${ctx.weight.observedKgPerWeek > 0 ? '+' : ''}${ctx.weight.observedKgPerWeek}kg`
              : '—'}
          </Text>
          <Text style={s.statLabel}>Weekly trend</Text>
        </View>
        <View style={s.statBox}>
          <Text style={s.statVal}>{ctx?.nutrition?.avgCaloriesLast7d ?? '—'}</Text>
          <Text style={s.statLabel}>
            Avg kcal {ctx?.nutrition?.targetCalories ? `(target ${ctx.nutrition.targetCalories})` : ''}
          </Text>
        </View>
        <View style={s.statBox}>
          <Text style={s.statVal}>
            {ctx?.workout?.sessionsCompletedLast7d ?? 0}
            <Text style={s.statValDim}>/{ctx?.workout?.sessionsPlannedPerWeek ?? '—'}</Text>
          </Text>
          <Text style={s.statLabel}>Sessions done</Text>
        </View>
      </View>
      <TouchableOpacity
        style={[s.adaptBtn, adapting && { opacity: 0.6 }]}
        onPress={adaptNow}
        disabled={adapting}
        activeOpacity={0.85}
      >
        {adapting
          ? <ActivityIndicator color={C.bg} />
          : <Text style={s.adaptBtnText}>⚡ Adapt Plan to This Week's Data</Text>}
      </TouchableOpacity>
      <Text style={s.adaptHint}>
        Uses your weight log, food log and session check-ins from the last 7 days.
      </Text>
    </View>
  );
}

const makeStyles = (C) => StyleSheet.create({
  adaptCard: { backgroundColor: C.card, borderRadius: 16, padding: 16, marginBottom: 14, borderWidth: 1, borderColor: C.border },
  adaptHeader: { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', marginBottom: 12 },
  adaptTitle: { color: C.white, fontSize: 15, fontWeight: '900', letterSpacing: 0.3 },
  adhPill: { backgroundColor: C.greenGlow2, paddingHorizontal: 10, paddingVertical: 4, borderRadius: 10 },
  adhPillText: { color: C.green, fontSize: 11, fontWeight: '900', letterSpacing: 0.5 },
  statsRow: { flexDirection: 'row', marginBottom: 14 },
  statBox: { flex: 1, backgroundColor: C.surface, borderRadius: 10, padding: 10, marginRight: 6, alignItems: 'center' },
  statVal: { color: C.green, fontSize: 18, fontWeight: '900' },
  statValDim: { color: C.muted, fontSize: 14, fontWeight: '700' },
  statLabel: { color: C.muted, fontSize: 10, marginTop: 4, textAlign: 'center' },
  adaptBtn: { backgroundColor: C.green, paddingVertical: 14, borderRadius: 12, alignItems: 'center' },
  adaptBtnText: { color: C.bg, fontSize: 14, fontWeight: '900', letterSpacing: 0.5 },
  adaptHint: { color: C.muted, fontSize: 11, textAlign: 'center', marginTop: 10, lineHeight: 16 },
});

import React from 'react';
import { View, Text, TouchableOpacity, StyleSheet, SafeAreaView } from 'react-native';
import { useTheme } from '../theme/ThemeContext';
import { select as hSelect } from '../utils/haptics';
const TABS = [
  { screen: 'home',    label: 'Home',      icon: '🏠' },
  { screen: 'plan',    label: 'Training',  icon: '🏋️' },
  { screen: 'scanner', label: 'AI Scan',   icon: '📷', center: true },
  { screen: 'foodlog', label: 'Nutrition', icon: '🍴' },
  { screen: 'profile', label: 'Profile',   icon: '👤' },
];

export default function BottomNav({ current, onNavigate }) {
  const { C } = useTheme();
  const s = makeStyles(C);
  return (
    <SafeAreaView style={s.safeArea}>
      <View style={s.bar}>
        {TABS.map(tab => {
          const active = current === tab.screen;
          return (
            <TouchableOpacity
              key={tab.screen}
              style={s.tab}
              onPress={() => { if (current !== tab.screen) hSelect(); onNavigate(tab.screen); }}
              activeOpacity={0.7}
            >
              <View style={[s.iconBox, active && s.iconBoxActive]}>
                <Text style={[s.iconText, active && s.iconTextActive]}>{tab.icon}</Text>
              </View>
              <Text style={[s.label, active && s.labelActive]}>{tab.label}</Text>
            </TouchableOpacity>
          );
        })}
      </View>
    </SafeAreaView>
  );
}

const makeStyles = (C) => StyleSheet.create({
  safeArea: { backgroundColor: C.surface, borderTopWidth: 1, borderTopColor: C.border },
  bar: { flexDirection: 'row', paddingTop: 8, paddingBottom: 6 },
  tab: { flex: 1, alignItems: 'center', paddingBottom: 4 },
  iconBox: { width: 44, height: 32, borderRadius: 12, alignItems: 'center', justifyContent: 'center', marginBottom: 3 },
  iconBoxActive: { backgroundColor: C.greenGlow },
  iconText: { color: C.muted, fontSize: 18 },
  iconTextActive: { color: C.green },
  label: { color: C.muted, fontSize: 10, fontWeight: '600' },
  labelActive: { color: C.green, fontWeight: '800' },
});

import React from 'react';
import { StyleSheet, Text, View } from 'react-native';
import { useTheme } from '../theme/ThemeContext';

export function hasMeaningfulChange(lastChange) {
  if (!lastChange) return false;
  const adj = Array.isArray(lastChange.adjustments) ? lastChange.adjustments : [];
  const wins = Array.isArray(lastChange.wins) ? lastChange.wins : [];
  if (adj.length > 0) return true;
  if (wins.length > 0) return true;
  return false;
}

export default function ChangeLogCard({ lastChange }) {
  const { C } = useTheme();
  const s = makeStyles(C);
  if (!hasMeaningfulChange(lastChange)) return null;

  const adj = Array.isArray(lastChange.adjustments) ? lastChange.adjustments : [];
  const wins = Array.isArray(lastChange.wins) ? lastChange.wins : [];
  const focus = Array.isArray(lastChange.focusNextWeek) ? lastChange.focusNextWeek : [];

  return (
    <View style={s.changeCard}>
      <Text style={s.changeLabel}>WHAT CHANGED LAST UPDATE</Text>
      {lastChange.summary ? (
        <Text style={s.changeSummary}>{lastChange.summary}</Text>
      ) : null}
      {adj.map((a, i) => (
        <View key={i} style={s.adjRow}>
          <Text style={s.adjArea}>{a.area}</Text>
          <Text style={s.adjBeforeAfter}>
            {a.before} <Text style={s.adjArrow}>→</Text> {a.after}
          </Text>
          {a.why ? <Text style={s.adjWhy}>{a.why}</Text> : null}
        </View>
      ))}
      {wins.length > 0 && (
        <View style={s.changeSubBlock}>
          <Text style={s.changeSubLabel}>WINS</Text>
          {wins.map((w, i) => (
            <Text key={i} style={s.changeBullet}>✓ {w}</Text>
          ))}
        </View>
      )}
      {focus.length > 0 && (
        <View style={s.changeSubBlock}>
          <Text style={s.changeSubLabel}>FOCUS NEXT WEEK</Text>
          {focus.map((f, i) => (
            <Text key={i} style={s.changeBullet}>→ {f}</Text>
          ))}
        </View>
      )}
    </View>
  );
}

const makeStyles = (C) => StyleSheet.create({
  changeCard: { backgroundColor: C.greenGlow2, borderRadius: 14, padding: 14, marginBottom: 14, borderLeftWidth: 3, borderLeftColor: C.green },
  changeLabel: { color: C.green, fontSize: 10, fontWeight: '900', letterSpacing: 2, marginBottom: 8 },
  changeSummary: { color: C.light, fontSize: 13, lineHeight: 20, marginBottom: 12 },
  adjRow: { marginBottom: 10 },
  adjArea: { color: C.white, fontSize: 12, fontWeight: '800', letterSpacing: 0.3, marginBottom: 2 },
  adjBeforeAfter: { color: C.light, fontSize: 13, fontWeight: '700' },
  adjArrow: { color: C.green, fontWeight: '900' },
  adjWhy: { color: C.muted, fontSize: 11, marginTop: 2, fontStyle: 'italic' },
  changeSubBlock: { marginTop: 10, paddingTop: 10, borderTopWidth: 1, borderTopColor: C.border },
  changeSubLabel: { color: C.green, fontSize: 9, fontWeight: '900', letterSpacing: 1.5, marginBottom: 6 },
  changeBullet: { color: C.mutedLight, fontSize: 12, lineHeight: 18, marginBottom: 3 },
});

import React, { useState, useEffect, useCallback, useRef } from 'react';
import {
  StyleSheet, Text, View, TouchableOpacity, TextInput, Modal,
  ScrollView, ActivityIndicator, Alert, Platform, KeyboardAvoidingView,
} from 'react-native';
import { useTheme } from '../theme/ThemeContext';
import {
  getFavorites, getYesterdayMeal, getUsualForSlot, parseMealDescription,
  appendToTodayLog, currentMealTime, loadPinnedFavorites, pinFavorite,
} from '../utils/quickLog';

const MEAL_TIMES = ['Breakfast', 'Morning Snack', 'Lunch', 'Afternoon Snack', 'Dinner', 'Late Snack'];

// Cross-platform speech recognition (web only)
function useSpeechToText(onResult) {
  const recRef = useRef(null);
  const supported = Platform.OS === 'web'
    && typeof window !== 'undefined'
    && (window.SpeechRecognition || window.webkitSpeechRecognition);

  const start = () => {
    if (!supported) return false;
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    const rec = new SR();
    rec.lang = 'en-US';
    rec.interimResults = false;
    rec.continuous = false;
    rec.onresult = (ev) => {
      const txt = Array.from(ev.results).map(r => r[0].transcript).join(' ');
      onResult(txt);
    };
    rec.onerror = () => {};
    rec.start();
    recRef.current = rec;
    return true;
  };
  const stop = () => { try { recRef.current?.stop(); } catch {} };
  return { supported, start, stop };
}

export default function QuickLogSheet({ visible, onClose, uid, onLogged }) {
  const { C } = useTheme();
  const s = makeStyles(C);

  const [pinned, setPinned] = useState([]);
  const [favorites, setFavorites] = useState([]);
  const [yesterday, setYesterday] = useState(null);
  const [usual, setUsual] = useState(null);
  const [slot, setSlot] = useState(currentMealTime());
  const [text, setText] = useState('');
  const [parsing, setParsing] = useState(false);
  const [parsed, setParsed] = useState(null);
  const [listening, setListening] = useState(false);
  const speech = useSpeechToText((txt) => { setText(txt); setListening(false); });

  const refresh = useCallback(async () => {
    const [pin, favs, ym, us] = await Promise.all([
      loadPinnedFavorites(uid),
      getFavorites(uid, 6),
      getYesterdayMeal(uid, slot),
      getUsualForSlot(uid, slot),
    ]);
    setPinned(pin);
    setFavorites(favs);
    setYesterday(ym);
    setUsual(us);
  }, [uid, slot]);

  useEffect(() => {
    if (visible) {
      setText('');
      setParsed(null);
      refresh();
    }
  }, [visible, refresh]);

  const logEntry = async (entry) => {
    const stripped = {
      name: entry.name,
      calories: entry.calories || 0,
      protein:  entry.protein  || 0,
      carbs:    entry.carbs    || 0,
      fat:      entry.fat      || 0,
      mealTime: slot,
    };
    await appendToTodayLog(uid, stripped);
    if (onLogged) onLogged();
    onClose();
  };

  const handleParse = async () => {
    if (!text.trim()) return;
    setParsing(true);
    try {
      const result = await parseMealDescription(text.trim());
      setParsed(result);
    } catch (e) {
      Alert.alert('Could not parse', e.message);
    } finally {
      setParsing(false);
    }
  };

  const handleVoice = () => {
    if (!speech.supported) {
      Alert.alert('Voice not supported here', 'Voice input works in your browser. Just type the meal below — we\'ll figure out the macros.');
      return;
    }
    setListening(true);
    if (!speech.start()) setListening(false);
  };

  return (
    <Modal visible={visible} transparent animationType="slide" onRequestClose={onClose}>
      <View style={s.backdrop}>
        <TouchableOpacity style={s.backdropTap} activeOpacity={1} onPress={onClose} />
        <KeyboardAvoidingView behavior={Platform.OS === 'ios' ? 'padding' : undefined} style={s.sheet}>
          <View style={s.handle} />
          <View style={s.headerRow}>
            <Text style={s.title}>Quick Log</Text>
            <TouchableOpacity onPress={onClose} style={s.xBtn}><Text style={s.xText}>✕</Text></TouchableOpacity>
          </View>

          <ScrollView contentContainerStyle={s.scroll} keyboardShouldPersistTaps="handled">
            <Text style={s.sectionLabel}>MEAL</Text>
            <View style={s.slotRow}>
              {MEAL_TIMES.map(m => (
                <TouchableOpacity
                  key={m}
                  style={[s.slotChip, slot === m && s.slotChipActive]}
                  onPress={() => setSlot(m)}
                >
                  <Text style={[s.slotChipText, slot === m && s.slotChipTextActive]}>{m}</Text>
                </TouchableOpacity>
              ))}
            </View>

            {/* One-tap repeats */}
            {(yesterday || usual) && (
              <>
                <Text style={s.sectionLabel}>ONE-TAP REPEAT</Text>
                {yesterday && (
                  <RepeatRow s={s} C={C} title={`Same as yesterday's ${slot}`} entry={yesterday} onLog={() => logEntry(yesterday)} />
                )}
                {usual && (!yesterday || usual.name !== yesterday.name) && (
                  <RepeatRow s={s} C={C} title={`What I usually have for ${slot}`} entry={usual} onLog={() => logEntry(usual)} />
                )}
              </>
            )}

            {pinned.length > 0 && (
              <>
                <Text style={s.sectionLabel}>PINNED</Text>
                {pinned.map(e => (
                  <RepeatRow key={'p_' + e.name} s={s} C={C} title={e.name} entry={e} subtitle={`${e.calories} kcal · ${e.protein}P/${e.carbs}C/${e.fat}F`} onLog={() => logEntry(e)} />
                ))}
              </>
            )}

            {favorites.length > 0 && (
              <>
                <Text style={s.sectionLabel}>FREQUENT MEALS</Text>
                {favorites.map(f => {
                  const e = f.sample;
                  const isPinned = pinned.find(p => (p.name || '').toLowerCase() === (e.name || '').toLowerCase());
                  return (
                    <View key={'f_' + f.name} style={s.favRow}>
                      <TouchableOpacity style={{ flex: 1 }} onPress={() => logEntry(e)} activeOpacity={0.8}>
                        <Text style={s.favTitle}>{e.name}</Text>
                        <Text style={s.favSub}>{f.count}× · {e.calories} kcal · {e.protein}P/{e.carbs}C/{e.fat}F</Text>
                      </TouchableOpacity>
                      <TouchableOpacity
                        onPress={async () => { await pinFavorite(uid, e); refresh(); }}
                        style={s.starBtn}
                      >
                        <Text style={[s.starText, isPinned && { color: C.green }]}>{isPinned ? '★' : '☆'}</Text>
                      </TouchableOpacity>
                    </View>
                  );
                })}
              </>
            )}

            {/* Free-text + voice */}
            <Text style={s.sectionLabel}>DESCRIBE A MEAL</Text>
            <View style={s.inputRow}>
              <TextInput
                style={s.input}
                value={text}
                onChangeText={setText}
                placeholder='e.g. "chicken caesar wrap with fries"'
                placeholderTextColor={C.muted}
                multiline
              />
              <TouchableOpacity style={[s.micBtn, listening && s.micBtnOn]} onPress={handleVoice}>
                <Text style={s.micText}>{listening ? '●' : '🎤'}</Text>
              </TouchableOpacity>
            </View>
            <TouchableOpacity
              style={[s.parseBtn, (!text.trim() || parsing) && s.parseBtnDisabled]}
              onPress={handleParse}
              disabled={!text.trim() || parsing}
            >
              {parsing
                ? <ActivityIndicator color={C.bg} />
                : <Text style={s.parseBtnText}>Estimate macros with AI</Text>}
            </TouchableOpacity>

            {parsed && (
              <View style={s.parsedCard}>
                <Text style={s.parsedName}>{parsed.name}</Text>
                <Text style={s.parsedConf}>AI confidence: {parsed.confidence}</Text>
                <View style={s.parsedMacros}>
                  <Macro v={parsed.calories} label="kcal" C={C} />
                  <Macro v={parsed.protein}  label="P" C={C} />
                  <Macro v={parsed.carbs}    label="C" C={C} />
                  <Macro v={parsed.fat}      label="F" C={C} />
                </View>
                <TouchableOpacity style={s.confirmBtn} onPress={() => logEntry(parsed)}>
                  <Text style={s.confirmBtnText}>ADD TO LOG</Text>
                </TouchableOpacity>
              </View>
            )}

            <View style={{ height: 30 }} />
          </ScrollView>
        </KeyboardAvoidingView>
      </View>
    </Modal>
  );
}

function RepeatRow({ s, C, title, subtitle, entry, onLog }) {
