  return (
    <View style={s.header}>
      <TouchableOpacity onPress={() => onNavigate('foodlog')} style={s.backBtn}>
        <Text style={s.backBtnText}>‹</Text>
      </TouchableOpacity>
      <Text style={s.headerTitle}>Scan Barcode</Text>
