            <View style={{ width: 6, height: 6, borderRadius: 3, backgroundColor: C.green, marginRight: 10 }} />
            <Text style={{ color: C.white, fontSize: 14, flex: 1 }}>{typeof ing === 'string' ? ing : ing.item}</Text>
