          <Text style={{ color: '#FF8A00', fontSize: 11, fontWeight: '900', letterSpacing: 0.5 }}>YOU'LL NEED</Text>
          <Text style={{ color: C.white, fontSize: 13, marginTop: 4 }}>{recipe.missingIngredients.join(' · ')}</Text>
