            <TouchableOpacity onPress={() => setProv(false)} style={{ marginTop: 10, paddingVertical: 14, borderRadius: 14, backgroundColor: C.green, alignItems: 'center' }}>
              <Text style={{ color: C.bg, fontWeight: '900' }}>Got it</Text>
