            onChange={(v) => updateField('birthday', v)}
          />
        );

      case 'height':
        if (data.units === 'Imperial') {
          const totalIn = parseFloat(data.heightIn || '') >= 0 || parseFloat(data.heightFt || '') >= 0
            ? (parseFloat(data.heightFt || '0') * 12 + parseFloat(data.heightIn || '0'))
