import React, { createContext, useContext, useEffect, useState, useCallback, useMemo } from 'react';
import { Appearance } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { darkC, lightC } from '../constants/theme';

const STORAGE_KEY = 'greengain_theme_mode';

const ThemeContext = createContext({
  mode: 'dark',
  C: darkC,
  setMode: () => {},
  toggle: () => {},
});

export function ThemeProvider({ children }) {
  const [mode, setModeState] = useState(() => Appearance.getColorScheme() === 'light' ? 'light' : 'dark');
  const [hydrated, setHydrated] = useState(false);

  useEffect(() => {
    (async () => {
      try {
        const saved = await AsyncStorage.getItem(STORAGE_KEY);
        if (saved === 'light' || saved === 'dark') {
          setModeState(saved);
        }
      } catch {}
      setHydrated(true);
    })();
  }, []);

  useEffect(() => {
    if (!hydrated) return;
    const sub = Appearance.addChangeListener(async ({ colorScheme }) => {
      try {
        const saved = await AsyncStorage.getItem(STORAGE_KEY);
        if (!saved && (colorScheme === 'light' || colorScheme === 'dark')) {
          setModeState(colorScheme);
        }
      } catch {}
    });
    return () => sub?.remove?.();
  }, [hydrated]);

  const setMode = useCallback(async (next) => {
    setModeState(next);
    try { await AsyncStorage.setItem(STORAGE_KEY, next); } catch {}
  }, []);

  const toggle = useCallback(() => {
    setMode(mode === 'dark' ? 'light' : 'dark');
  }, [mode, setMode]);

  const value = useMemo(() => ({
    mode,
    C: mode === 'light' ? lightC : darkC,
    setMode,
    toggle,
  }), [mode, setMode, toggle]);

  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
}

export function useTheme() {
  return useContext(ThemeContext);
}

const GROQ_KEY = process.env.EXPO_PUBLIC_GROQ_KEY || '';
const GROQ_URL = 'https://api.groq.com/openai/v1/chat/completions';

// Text-only AI call
export const callAI = async (systemPrompt, userMessage) => {
  if (!GROQ_KEY) throw new Error('Missing EXPO_PUBLIC_GROQ_KEY in your .env file');

  const response = await fetch(GROQ_URL, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': 'Bearer ' + GROQ_KEY,
    },
    body: JSON.stringify({
      model: 'llama-3.3-70b-versatile',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user',   content: userMessage  },
      ],
      max_tokens: 4000,
      temperature: 0.7,
    }),
  });

  if (!response.ok) {
    const err = await response.json().catch(() => ({}));
    throw new Error(err?.error?.message || 'API error ' + response.status);
  }

  const data = await response.json();
  return data.choices?.[0]?.message?.content || '';
};

// Vision call - Groq supports vision via llama-4 scout
export const callAIWithImage = async (base64Image, mimeType, userText, systemPromptOverride) => {
  if (!GROQ_KEY) throw new Error('Missing EXPO_PUBLIC_GROQ_KEY in your .env file');

  const defaultSystem = 'You are a professional nutritionist with expert ability to identify food from photos. Return ONLY valid JSON with no markdown and no extra text. Use this exact structure: {"meal":"descriptive meal name","calories":number,"protein":number,"carbs":number,"fat":number,"fiber":number,"sugar":number,"sodium":number,"servingSize":"estimated portion","healthScore":number,"ingredients":["item1","item2"],"tips":["tip1","tip2"]}. All macros in grams. healthScore is 1-10.';
  const systemText = systemPromptOverride || defaultSystem;

  const userContent = [
    {
      type: 'image_url',
      image_url: { url: 'data:' + mimeType + ';base64,' + base64Image },
    },
    {
      type: 'text',
      text: systemPromptOverride
        ? (userText || 'Analyze this image as instructed.')
        : (userText
            ? 'Analyze this meal photo. Extra context: ' + userText
            : 'Analyze this meal photo and return the nutrition facts.'),
    },
  ];

  const response = await fetch(GROQ_URL, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': 'Bearer ' + GROQ_KEY,
    },
    body: JSON.stringify({
      model: 'meta-llama/llama-4-scout-17b-16e-instruct',
      messages: [
        { role: 'system', content: systemText },
        { role: 'user',   content: userContent },
      ],
      max_tokens: 2000,
      temperature: 0.4,
    }),
  });

  if (!response.ok) {
    const err = await response.json().catch(() => ({}));
    throw new Error(err?.error?.message || 'API error ' + response.status);
  }

  const data = await response.json();
  return data.choices?.[0]?.message?.content || '';
};

export const parseJSON = (raw, fallback) => {
  if (!raw) return fallback;
  try {
    return JSON.parse(raw.replace(/```json/gi, '').replace(/```/g, '').trim());
  } catch {
    try {
      const start = raw.indexOf('{');
      const end   = raw.lastIndexOf('}');
      if (start !== -1 && end !== -1) return JSON.parse(raw.slice(start, end + 1));
    } catch {}
    return fallback;
  }
};

import AsyncStorage from '@react-native-async-storage/async-storage';
import { doc, setDoc, getDoc, updateDoc } from 'firebase/firestore';
import { db } from './firebase';

const SESSION_KEY = 'greengain_session_v2';

const hashPassword = (password) => {
  let hash = 5381;
  for (let i = 0; i < password.length; i++) {
    hash = ((hash << 5) + hash) + password.charCodeAt(i);
    hash = hash & hash;
  }
  return 'fl_' + Math.abs(hash).toString(16) + '_' + password.length;
};

const emailToId = (email) => {
  return email.toLowerCase().trim()
    .replace(/@/g, '__at__')
    .replace(/\./g, '__dot__');
};

export const Auth = {
  onAuthChange(callback) {
    Auth.getSession().then(user => callback(user));
    return () => {};
  },

  async signup(fullName, email, password) {
    try {
      const uid     = emailToId(email);
      const userRef = doc(db, 'users', uid);
      const existing = await getDoc(userRef);

      if (existing.exists()) {
        return { error: 'An account with this email already exists.' };
      }

      const userData = {
        fullName: fullName.trim(),
        email: email.toLowerCase().trim(),
        uid,
        passwordHash: hashPassword(password),
        createdAt: Date.now(),
        mealsScanned: 0,
        workoutsLogged: 0,
        streak: 0,
        lastActive: null,
      };

      await setDoc(userRef, userData);
      await AsyncStorage.setItem(SESSION_KEY, JSON.stringify({ uid }));
      return { user: userData };
    } catch (e) {
      console.error('Signup error:', e);
      return { error: 'Signup failed. Check your internet connection.' };
    }
  },

  async login(email, password) {
    try {
      const uid     = emailToId(email);
      const userRef = doc(db, 'users', uid);
      const snap    = await getDoc(userRef);

      if (!snap.exists()) {
        return { error: 'No account found with this email.' };
      }

      const userData = snap.data();
      if (userData.passwordHash !== hashPassword(password)) {
        return { error: 'Incorrect password.' };
      }

      await AsyncStorage.setItem(SESSION_KEY, JSON.stringify({ uid }));
      return { user: { ...userData, uid } };
    } catch (e) {
      console.error('Login error:', e);
      return { error: 'Login failed. Check your internet connection.' };
    }
  },

  async logout() {
    await AsyncStorage.removeItem(SESSION_KEY);
  },

  async getSession() {
    try {
      const raw = await AsyncStorage.getItem(SESSION_KEY);
      if (!raw) return null;
      const { uid } = JSON.parse(raw);
      if (!uid) return null;
      return await Auth.getUserData(uid);
    } catch { return null; }
  },

  async getUserData(uid) {
    try {
      const snap = await getDoc(doc(db, 'users', uid));
      return snap.exists() ? { ...snap.data(), uid } : null;
    } catch { return null; }
  },

  async updateUser(uid, updates) {
    try {
      await updateDoc(doc(db, 'users', uid), updates);
      return await Auth.getUserData(uid);
    } catch { return null; }
  },

  async logActivity(uid) {
    try {
      const user = await Auth.getUserData(uid);
      if (!user) return null;
      const today     = new Date().toDateString();
      const yesterday = new Date(Date.now() - 86400000).toDateString();
      let streak = user.streak || 0;
      if (user.lastActive === today) {
      } else if (user.lastActive === yesterday) {
        streak += 1;
      } else {
        streak = 1;
      }
      await updateDoc(doc(db, 'users', uid), { streak, lastActive: today });
      return await Auth.getUserData(uid);
    } catch { return null; }
  },
};

import { Storage, KEYS } from './storage';
import { getHealthDay } from './health';

const dateOnly = (d) => d.toDateString();

function pillarsFor({ foodLog, plan, healthDay, adherenceForDay, plannedDayType }) {
  const totals = (foodLog || []).reduce((acc, item) => ({
    calories: acc.calories + (item.calories || 0),
    protein:  acc.protein  + (item.protein  || 0),
  }), { calories: 0, protein: 0 });

  const calTarget = plan?.dailyCalories || 0;
  const protTarget = plan?.protein || 0;
  const stepsTarget = plan?.stepsTarget || 8000;

  // Calorie pillar: within ±10% of target (90%–110%); or any food logged if no target
  const calOk = calTarget
    ? totals.calories >= calTarget * 0.90 && totals.calories <= calTarget * 1.10
    : totals.calories > 0;

  // Protein pillar: at least 90% of target
  const protOk = protTarget
    ? totals.protein >= protTarget * 0.9
    : totals.protein >= 80;

  // Workout pillar: completed; OR today is a planned rest day (auto ✓)
  const isRestDay = plannedDayType ? /rest/i.test(plannedDayType) : false;
  const workoutOk = isRestDay || !!(adherenceForDay && adherenceForDay.completed);

  // Steps pillar
  const steps = healthDay?.steps || 0;
  const stepsOk = steps >= stepsTarget;

  return {
    calories: { ok: calOk, value: Math.round(totals.calories), target: calTarget, label: 'Calories' },
    protein:  { ok: protOk, value: Math.round(totals.protein),  target: protTarget, label: 'Protein' },
    workout:  { ok: workoutOk, value: workoutOk ? '✓' : '—', target: 1, label: 'Workout' },
    steps:    { ok: stepsOk, value: steps, target: stepsTarget, label: 'Steps' },
  };
}

function plannedDayTypeFor(plan, date) {
  if (!Array.isArray(plan?.workoutPlan) || !plan.workoutPlan.length) return null;
  const dayNames = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
  const name = dayNames[date.getDay()];
  const entry = plan.workoutPlan.find(w => (w.day || '').toLowerCase() === name.toLowerCase());
  return entry?.type || null;
}

export async function computeTodayScore(uid, plan, foodLog, healthToday) {
  const adherence = (await Storage.get(KEYS.ADHERENCE(uid))) || [];
  const today = new Date();
  const todayStr = today.toDateString();
  const todayAdh = adherence.find(e => e.date === todayStr);
  const pillars = pillarsFor({
    foodLog, plan, healthDay: healthToday,
    adherenceForDay: todayAdh,
    plannedDayType: plannedDayTypeFor(plan, today),
  });
  const hits = Object.values(pillars).filter(p => p.ok).length;
  return { pillars, hits, total: 4 };
}

// Compute scores for the past N days (newest last).
// Each day returns { date, label, hits } where hits is 0..4.
export async function computeRecentScores(uid, plan, days = 7, healthUid = uid) {
  const adherence = (await Storage.get(KEYS.ADHERENCE(uid))) || [];
  const out = [];
  const today = new Date();
  for (let i = days - 1; i >= 0; i--) {
    const d = new Date(today);
    d.setDate(today.getDate() - i);
    const dateStr = d.toDateString();
    const [foodLog, healthDay] = await Promise.all([
      Storage.get(KEYS.FOODLOG(uid, dateStr)),
      getHealthDay(healthUid, d),
    ]);
    const adh = adherence.find(e => e.date === dateStr);
    const pillars = pillarsFor({
      foodLog, plan, healthDay, adherenceForDay: adh,
      plannedDayType: plannedDayTypeFor(plan, d),
    });
    const hits = Object.values(pillars).filter(p => p.ok).length;
    out.push({
      date: dateStr,
      label: d.toLocaleDateString('en-US', { weekday: 'short' })[0],
      day: d.getDate(),
      hits,
      isToday: i === 0,
    });
  }
  return out;
}

// A day "counts" toward a streak when at least 2 of 4 pillars hit.
export function streakFromScores(scores, threshold = 2) {
  let streak = 0;
  for (let i = scores.length - 1; i >= 0; i--) {
    if (scores[i].hits >= threshold) streak += 1;
    else if (scores[i].isToday) {
      // grace: if today is incomplete (0 hits), don't break the streak yet
      if (scores[i].hits === 0) continue;
      else break;
    } else break;
  }
  return streak;
}

