/**
 * Optional wearable / Health data sources.
 *
 * Apple Health (iOS) and Health Connect (Android) require native modules that
 * are NOT available in Expo Go. To use real Garmin / Whoop / Apple data,
 * users must install one of:
 *   - react-native-health         (iOS HealthKit)
 *   - react-native-health-connect (Android Health Connect)
 * AND build a custom dev client with `eas build --profile development`.
 *
 * We dynamically import these so the app keeps working in Expo Go and on web —
 * if the package isn't present we report the source as unavailable.
 */
import { Platform } from 'react-native';

let _appleHealth = null;       // react-native-health
let _healthConnect = null;     // react-native-health-connect
let _initialized = false;

async function tryLoad() {
  if (_initialized) return;
  _initialized = true;
  if (Platform.OS === 'ios') {
    try { _appleHealth = (await import('react-native-health')).default || (await import('react-native-health')); }
    catch { _appleHealth = null; }
  } else if (Platform.OS === 'android') {
    try { _healthConnect = await import('react-native-health-connect'); }
    catch { _healthConnect = null; }
  }
}

export async function isAppleHealthAvailable() {
  await tryLoad();
  return Platform.OS === 'ios' && !!_appleHealth;
}
export async function isHealthConnectAvailable() {
  await tryLoad();
  return Platform.OS === 'android' && !!_healthConnect;
}

const APPLE_PERMS = {
  permissions: {
    read: ['Steps', 'StepCount', 'HeartRate', 'RestingHeartRate',
           'SleepAnalysis', 'ActiveEnergyBurned', 'Workout'],
    write: [],
  },
};

export async function connectAppleHealth() {
  await tryLoad();
  if (!_appleHealth) return { ok: false, reason: 'unavailable' };
  return await new Promise((resolve) => {
    try {
      _appleHealth.initHealthKit(APPLE_PERMS, (err) => {
        if (err) resolve({ ok: false, reason: err.message || 'denied' });
        else resolve({ ok: true });
      });
    } catch (e) {
      resolve({ ok: false, reason: e?.message || 'init failed' });
    }
  });
}

export async function connectHealthConnect() {
  await tryLoad();
  if (!_healthConnect) return { ok: false, reason: 'unavailable' };
  try {
    const init = await _healthConnect.initialize();
    if (!init) return { ok: false, reason: 'not initialized' };
    const granted = await _healthConnect.requestPermission([
      { accessType: 'read', recordType: 'Steps' },
      { accessType: 'read', recordType: 'HeartRate' },
      { accessType: 'read', recordType: 'SleepSession' },
      { accessType: 'read', recordType: 'ActiveCaloriesBurned' },
    ]);
    return { ok: !!granted?.length };
  } catch (e) {
    return { ok: false, reason: e?.message || 'permission failed' };
  }
}

function startEndOfToday() {
  const start = new Date(); start.setHours(0, 0, 0, 0);
  const end = new Date(); end.setHours(23, 59, 59, 999);
  return { start, end };
}

export async function fetchTodayFromAppleHealth() {
  await tryLoad();
  if (!_appleHealth) return null;
  const { start, end } = startEndOfToday();
  const opts = { startDate: start.toISOString(), endDate: end.toISOString() };
  const res = {};
  await Promise.all([
    new Promise(r => _appleHealth.getStepCount(opts, (e, v) => { if (!e && v?.value != null) res.steps = Math.round(v.value); r(); })),
    new Promise(r => _appleHealth.getRestingHeartRate(opts, (e, v) => { if (!e && v?.value != null) res.restingHr = Math.round(v.value); r(); })),
    new Promise(r => _appleHealth.getActiveEnergyBurned(opts, (e, v) => { if (!e && v?.[0]?.value != null) res.activeMin = Math.round((v[0].value || 0) / 5); r(); })),
    new Promise(r => _appleHealth.getSleepSamples(opts, (e, v) => {
      if (!e && Array.isArray(v) && v.length) {
        const totalMs = v.reduce((acc, s) => {
          const a = new Date(s.startDate).getTime();
          const b = new Date(s.endDate).getTime();
          return acc + Math.max(0, b - a);
        }, 0);
        res.sleepHr = +(totalMs / 3_600_000).toFixed(1);
      }
      r();
    })),
  ]);
  return res;
}

export async function fetchTodayFromHealthConnect() {
  await tryLoad();
  if (!_healthConnect) return null;
  const { start, end } = startEndOfToday();
  const range = { operator: 'between', startTime: start.toISOString(), endTime: end.toISOString() };
  const res = {};
  try {
    const steps = await _healthConnect.readRecords('Steps', { timeRangeFilter: range });
    res.steps = (steps?.records || []).reduce((s, r) => s + (r.count || 0), 0);
  } catch {}
  try {
    const hr = await _healthConnect.readRecords('HeartRate', { timeRangeFilter: range });
    const samples = (hr?.records || []).flatMap(r => r.samples || []);
    const bpms = samples.map(s => s.beatsPerMinute).filter(n => typeof n === 'number');
    if (bpms.length) res.avgHr = Math.round(bpms.reduce((a, b) => a + b, 0) / bpms.length);
  } catch {}
  try {
    const cals = await _healthConnect.readRecords('ActiveCaloriesBurned', { timeRangeFilter: range });
    const totalCal = (cals?.records || []).reduce((s, r) => s + (r.energy?.inKilocalories || 0), 0);
    if (totalCal) res.activeMin = Math.round(totalCal / 5);
  } catch {}
  try {
    const sleep = await _healthConnect.readRecords('SleepSession', { timeRangeFilter: range });
    const totalMs = (sleep?.records || []).reduce((acc, r) => {
      const a = new Date(r.startTime).getTime();
      const b = new Date(r.endTime).getTime();
      return acc + Math.max(0, b - a);
    }, 0);
    if (totalMs) res.sleepHr = +(totalMs / 3_600_000).toFixed(1);
  } catch {}
  return res;
}

import { Storage, KEYS } from './storage';
import { callAI, parseJSON } from './api';
import { buildWeeklyContext } from './planAdapter';

const weekKey = (d = new Date()) => {
  const day = d.getDay(); // 0=Sun
  const sunday = new Date(d);
  sunday.setDate(d.getDate() - day);
  sunday.setHours(0, 0, 0, 0);
  return sunday.toISOString().slice(0, 10);
};

export async function getLatestReview(uid) {
  const list = (await Storage.get(KEYS.WEEKLY_REVIEW(uid))) || [];
  return list[list.length - 1] || null;
}

export async function getAllReviews(uid) {
  return (await Storage.get(KEYS.WEEKLY_REVIEW(uid))) || [];
}

export function isReviewDue(latestReview) {
  // Show banner on Sundays + Mondays unless we already have one for the current week.
  const today = new Date();
  const weekday = today.getDay(); // 0=Sun, 1=Mon
  const todayWeek = weekKey(today);
  if (latestReview?.weekStart === todayWeek) return false;
  return weekday === 0 || weekday === 1;
}

export async function markReviewSeen(uid, weekStart) {
  const list = (await Storage.get(KEYS.WEEKLY_REVIEW(uid))) || [];
  const next = list.map(r => r.weekStart === weekStart ? { ...r, seen: true } : r);
  await Storage.set(KEYS.WEEKLY_REVIEW(uid), next);
  return next;
}

const SYSTEM = `You are an elite personal coach (strength + nutrition). Given a user's last 7 days of self-tracked data, write a brief weekly review. Be specific, kind, and practical. Reference their actual numbers. Return ONLY valid JSON, no markdown:
{
  "title": "short headline (max 8 words)",
  "summary": "2-3 sentence honest recap of the week",
  "wins": ["concrete thing they did well", "another"],
  "misses": ["concrete thing that slipped", "another"],
  "adjustments": ["one specific change to make next week", "another"],
  "nextFocus": "the ONE thing to prioritize next week (1 sentence)"
}`;

export async function generateWeeklyReview(uid, plan) {
  const ctx = await buildWeeklyContext(uid, plan);
  const profile = plan?.userProfile || {};
  const userMsg = `User profile: ${profile.gender || '?'}, ${profile.age || '?'}y, ${profile.weight || '?'}kg, goal: ${profile.goal || '?'} (target ${profile.targetWeight || '?'}kg).
Plan targets: ${plan?.dailyCalories || '?'} kcal, ${plan?.protein || '?'}g protein, ${plan?.carbs || '?'}g carbs, ${plan?.fat || '?'}g fat.
Last 7 days observed:
- Weight: latest ${ctx?.weight?.latest ?? '?'}kg, change ${ctx?.weight?.observedKgPerWeek ?? '?'}kg/wk
- Nutrition: avg ${ctx?.nutrition?.avgCaloriesLast7d ?? '?'} kcal (${ctx?.nutrition?.calorieDeltaVsTarget >= 0 ? '+' : ''}${ctx?.nutrition?.calorieDeltaVsTarget ?? '?'} vs target), avg ${ctx?.nutrition?.avgProteinLast7d ?? '?'}g protein, logged on ${ctx?.nutrition?.loggingDays ?? '?'}/7 days
- Workouts: ${ctx?.workout?.sessionsCompletedLast7d ?? 0} done, ${ctx?.workout?.sessionsSkippedLast7d ?? 0} skipped (${ctx?.workout?.adherencePct ?? '?'}% adherence)
- Health: avg ${ctx?.health?.avgStepsLast7d ?? '?'} steps/day, ${ctx?.health?.avgSleepHrLast7d ?? '?'}h sleep, inferred activity: ${ctx?.health?.inferredActivityLevel ?? '?'}

Write the JSON review now.`;

  const raw = await callAI(SYSTEM, userMsg);
  const parsed = parseJSON(raw, null);
  if (!parsed) throw new Error('Could not parse AI response');

  const review = {
    weekStart: weekKey(),
    generatedAt: Date.now(),
    seen: false,
    context: ctx,
    ...parsed,
  };

  const list = (await Storage.get(KEYS.WEEKLY_REVIEW(uid))) || [];
  // replace if same week
  const filtered = list.filter(r => r.weekStart !== review.weekStart);
  const next = [...filtered, review].slice(-12);
  await Storage.set(KEYS.WEEKLY_REVIEW(uid), next);
  return review;
}

import { Storage, KEYS } from './storage';

export const parseSetsCount = (v) => {
  if (typeof v === 'number') return Math.max(1, Math.min(10, Math.round(v)));
  if (!v) return 3;
  const m = String(v).match(/(\d+)/);
  return m ? Math.max(1, Math.min(10, parseInt(m[1], 10))) : 3;
};

export const parseRestSeconds = (rest) => {
  if (!rest) return 90;
  const s = String(rest).toLowerCase();
  const min = s.match(/(\d+(?:\.\d+)?)\s*(?:min|m)\b/);
  const sec = s.match(/(\d+)\s*s\b/);
  let total = 0;
  if (min) total += parseFloat(min[1]) * 60;
  if (sec) total += parseInt(sec[1], 10);
  if (!total) {
    // try ranges like "2-3 min"
    const range = s.match(/(\d+)\s*-\s*(\d+)\s*(min|m)?/);
    if (range) {
      const lo = parseInt(range[1], 10);
      const hi = parseInt(range[2], 10);
      total = ((lo + hi) / 2) * (range[3] ? 60 : 1);
    }
  }
  if (!total) {
    const just = s.match(/^(\d+)$/);
    if (just) total = parseInt(just[1], 10);
  }
  return Math.max(15, Math.min(600, Math.round(total) || 90));
};

const exKey = (name) => String(name || '').toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim();

export async function loadHistory(uid) {
  const h = await Storage.get(KEYS.WORKOUT_HISTORY(uid));
  return Array.isArray(h) ? h : [];
}

export async function getLastForExercise(uid, exerciseName) {
  const hist = await loadHistory(uid);
  const key = exKey(exerciseName);
  for (let i = hist.length - 1; i >= 0; i--) {
    const session = hist[i];
    const ex = (session.exercises || []).find(e => exKey(e.name) === key);
    if (ex && Array.isArray(ex.sets) && ex.sets.some(s => s.completed)) {
      return { session, sets: ex.sets.filter(s => s.completed), date: session.date };
    }
  }
  return null;
}

export async function saveSession(uid, session) {
  const hist = await loadHistory(uid);
  const next = [...hist, session].slice(-200);
  return Storage.set(KEYS.WORKOUT_HISTORY(uid), next);
}

export async function loadActive(uid) {
  return Storage.get(KEYS.ACTIVE_WORKOUT(uid));
}

export async function saveActive(uid, draft) {
  return Storage.set(KEYS.ACTIVE_WORKOUT(uid), draft);
}

export async function clearActive(uid) {
  return Storage.set(KEYS.ACTIVE_WORKOUT(uid), null);
}

export function buildInitialDraft(workoutDay) {
  return {
    day: workoutDay.day,
    type: workoutDay.type,
    focus: workoutDay.focus,
    startedAt: Date.now(),
    warmupDone: {},
    cooldownDone: {},
    exercises: (workoutDay.exercises || []).map((e) => {
      const exObj = typeof e === 'string' ? { name: e } : e;
      const setCount = parseSetsCount(exObj.sets);
      return {
        name: exObj.name || 'Exercise',
        targetSets: setCount,
        targetReps: exObj.reps || '',
        targetRpe:  exObj.rpe  || '',
        rest: exObj.rest || '',
        notes: exObj.notes || '',
        sets: Array.from({ length: setCount }, () => ({ weight: '', reps: '', rpe: '', completed: false })),
      };
    }),
  };
}

export function totalVolume(draft) {
  let vol = 0;
  let setsDone = 0;
  (draft.exercises || []).forEach(ex =>
    (ex.sets || []).forEach(s => {
      if (!s.completed) return;
      setsDone += 1;
      const w = parseFloat(s.weight) || 0;
      const r = parseFloat(s.reps) || 0;
      vol += w * r;
    })
  );
  return { volume: Math.round(vol), setsDone };
}
